import{_ as a,o as r,c as o,ae as t}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"개발 컨테이너","description":"일관되고 안전한 환경이 필요한 팀을 위한 Claude Code 개발 컨테이너에 대해 알아보세요.","frontmatter":{"title":"개발 컨테이너","description":"일관되고 안전한 환경이 필요한 팀을 위한 Claude Code 개발 컨테이너에 대해 알아보세요."},"headers":[],"relativePath":"devcontainer.md","filePath":"devcontainer.md","lastUpdated":1776205703000}'),i={name:"devcontainer.md"};function n(l,e,d,s,c,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="개발-컨테이너" tabindex="-1">개발 컨테이너 <a class="header-anchor" href="#개발-컨테이너" aria-label="Permalink to &quot;개발 컨테이너&quot;">​</a></h1><p>레퍼런스 <a href="https://github.com/anthropics/claude-code/tree/main/.devcontainer" target="_blank" rel="noreferrer">devcontainer 설정</a>과 관련 <a href="https://github.com/anthropics/claude-code/blob/main/.devcontainer/Dockerfile" target="_blank" rel="noreferrer">Dockerfile</a>은 그대로 사용하거나 필요에 맞게 커스터마이즈할 수 있는 사전 구성된 개발 컨테이너를 제공합니다. 이 devcontainer는 Visual Studio Code <a href="https://code.visualstudio.com/docs/devcontainers/containers" target="_blank" rel="noreferrer">Dev Containers 확장</a> 및 유사한 도구와 함께 작동합니다.</p><p>컨테이너의 강화된 보안 조치(격리 및 방화벽 규칙)를 통해 <code>claude --dangerously-skip-permissions</code>를 실행하여 무인 운영 시 권한 프롬프트를 건너뛸 수 있습니다.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>devcontainer는 상당한 보호를 제공하지만, 어떤 시스템도 모든 공격에 완전히 면역이 되지는 않습니다. <code>--dangerously-skip-permissions</code>로 실행할 때, devcontainer는 악의적인 프로젝트가 Claude Code 자격 증명을 포함하여 devcontainer에서 접근 가능한 모든 것을 유출하는 것을 방지하지 못합니다. 신뢰할 수 있는 저장소에서 개발할 때만 devcontainer를 사용하는 것을 권장합니다. 항상 좋은 보안 관행을 유지하고 Claude의 활동을 모니터링하세요.</p></div><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>프로덕션 준비된 Node.js</strong>: 필수 개발 의존성과 함께 Node.js 20 기반으로 구축</li><li><strong>설계부터 보안</strong>: 필요한 서비스에만 네트워크 접근을 제한하는 커스텀 방화벽</li><li><strong>개발자 친화적 도구</strong>: git, 생산성 향상 기능이 포함된 ZSH, fzf 등 포함</li><li><strong>원활한 VS Code 통합</strong>: 사전 구성된 확장 및 최적화된 설정</li><li><strong>세션 지속성</strong>: 컨테이너 재시작 간 명령 기록 및 구성 보존</li><li><strong>어디서나 작동</strong>: macOS, Windows, Linux 개발 환경과 호환</li></ul><h2 id="_4단계로-시작하기" tabindex="-1">4단계로 시작하기 <a class="header-anchor" href="#_4단계로-시작하기" aria-label="Permalink to &quot;4단계로 시작하기&quot;">​</a></h2><ol><li>VS Code와 <a href="https://marketplace.visualstudio.com/items?itemName=ms-vscode-remote.remote-containers" target="_blank" rel="noreferrer">Dev Containers 확장</a>을 설치합니다</li><li><a href="https://github.com/anthropics/claude-code/tree/main/.devcontainer" target="_blank" rel="noreferrer">Claude Code 레퍼런스 구현</a> 저장소를 클론합니다</li><li>VS Code에서 저장소를 엽니다</li><li>프롬프트가 표시되면 &quot;Reopen in Container&quot;를 클릭합니다 (또는 Command Palette: Cmd+Shift+P → &quot;Dev Containers: Reopen in Container&quot;)</li></ol><p>컨테이너 빌드가 완료되면 VS Code에서 <code>Ctrl+`</code>로 터미널을 열고 <code>claude</code>를 실행하여 인증하고 첫 번째 세션을 시작하세요. 컨테이너에는 Claude Code가 사전 설치되어 있으므로 즉시 작업을 시작할 수 있습니다. 프로젝트 파일은 컨테이너에 마운트되며, Claude가 작성하는 모든 코드는 로컬 저장소에 나타납니다.</p><h2 id="구성-분석" tabindex="-1">구성 분석 <a class="header-anchor" href="#구성-분석" aria-label="Permalink to &quot;구성 분석&quot;">​</a></h2><p>devcontainer 설정은 세 가지 주요 구성 요소로 이루어져 있습니다:</p><ul><li><a href="https://github.com/anthropics/claude-code/blob/main/.devcontainer/devcontainer.json" target="_blank" rel="noreferrer"><strong>devcontainer.json</strong></a>: 컨테이너 설정, 확장 및 볼륨 마운트를 제어합니다</li><li><a href="https://github.com/anthropics/claude-code/blob/main/.devcontainer/Dockerfile" target="_blank" rel="noreferrer"><strong>Dockerfile</strong></a>: 컨테이너 이미지 및 설치된 도구를 정의합니다</li><li><a href="https://github.com/anthropics/claude-code/blob/main/.devcontainer/init-firewall.sh" target="_blank" rel="noreferrer"><strong>init-firewall.sh</strong></a>: 네트워크 보안 규칙을 설정합니다</li></ul><h2 id="보안-기능" tabindex="-1">보안 기능 <a class="header-anchor" href="#보안-기능" aria-label="Permalink to &quot;보안 기능&quot;">​</a></h2><p>컨테이너는 방화벽 구성을 통해 다층 보안 접근 방식을 구현합니다:</p><ul><li><strong>정밀한 접근 제어</strong>: 화이트리스트된 도메인(npm 레지스트리, GitHub, Claude API 등)에만 아웃바운드 연결을 제한합니다</li><li><strong>허용된 아웃바운드 연결</strong>: 방화벽은 아웃바운드 DNS 및 SSH 연결을 허용합니다</li><li><strong>기본 거부 정책</strong>: 다른 모든 외부 네트워크 접근을 차단합니다</li><li><strong>시작 검증</strong>: 컨테이너 초기화 시 방화벽 규칙을 검증합니다</li><li><strong>격리</strong>: 메인 시스템과 분리된 안전한 개발 환경을 생성합니다</li></ul><h2 id="커스터마이즈-옵션" tabindex="-1">커스터마이즈 옵션 <a class="header-anchor" href="#커스터마이즈-옵션" aria-label="Permalink to &quot;커스터마이즈 옵션&quot;">​</a></h2><p>devcontainer 구성은 필요에 맞게 조정할 수 있도록 설계되었습니다:</p><ul><li>워크플로에 따라 VS Code 확장을 추가하거나 제거</li><li>다양한 하드웨어 환경에 맞게 리소스 할당 수정</li><li>네트워크 접근 권한 조정</li><li>셸 구성 및 개발자 도구 커스터마이즈</li></ul><h2 id="사용-사례-예시" tabindex="-1">사용 사례 예시 <a class="header-anchor" href="#사용-사례-예시" aria-label="Permalink to &quot;사용 사례 예시&quot;">​</a></h2><h3 id="보안-클라이언트-작업" tabindex="-1">보안 클라이언트 작업 <a class="header-anchor" href="#보안-클라이언트-작업" aria-label="Permalink to &quot;보안 클라이언트 작업&quot;">​</a></h3><p>devcontainer를 사용하여 서로 다른 클라이언트 프로젝트를 격리하고, 코드와 자격 증명이 환경 간에 혼합되지 않도록 합니다.</p><h3 id="팀-온보딩" tabindex="-1">팀 온보딩 <a class="header-anchor" href="#팀-온보딩" aria-label="Permalink to &quot;팀 온보딩&quot;">​</a></h3><p>새로운 팀원이 필요한 모든 도구와 설정이 사전 설치된 완전히 구성된 개발 환경을 몇 분 안에 갖출 수 있습니다.</p><h3 id="일관된-ci-cd-환경" tabindex="-1">일관된 CI/CD 환경 <a class="header-anchor" href="#일관된-ci-cd-환경" aria-label="Permalink to &quot;일관된 CI/CD 환경&quot;">​</a></h3><p>CI/CD 파이프라인에서 devcontainer 구성을 미러링하여 개발과 프로덕션 환경이 일치하도록 합니다.</p><h2 id="관련-리소스" tabindex="-1">관련 리소스 <a class="header-anchor" href="#관련-리소스" aria-label="Permalink to &quot;관련 리소스&quot;">​</a></h2><ul><li><a href="https://code.visualstudio.com/docs/devcontainers/containers" target="_blank" rel="noreferrer">VS Code devcontainers 문서</a></li><li><a href="/claude-code-docs-ko/security.html">Claude Code 보안 모범 사례</a></li><li><a href="/claude-code-docs-ko/network-config.html">엔터프라이즈 네트워크 구성</a></li></ul>',27)])])}const m=a(i,[["render",n]]);export{p as __pageData,m as default};
